// gen_heroes2 — 5 new playable characters (hunter recolours). File-body form.
// All ids + sprites use the h2_ prefix. Passives are modest, trade-off driven
// (game is being rebalanced harder — no stacked survivability).
//
// NOTE for the achievement/unlock system:
//   Two characters use NEW achievement condition strings that
//   `checkCharacterUnlocks` in characters.js does not yet honor. They load and
//   run fine (an unrecognised condition is simply skipped — no throw), but the
//   two hidden heroes will not auto-unlock until that function is extended with:
//     - 'kills_5000'  -> unlock when (META.stats.kills || 0) >= 5000
//                        (cumulative lifetime kills; META.stats.kills already exists)
//     - 'survive_600' -> unlock when a single run survives >= 600 seconds.
//                        Track e.g. META.stats.bestTime = Math.max(bestTime, run.time)
//                        in run.js end-of-run handling, then test bestTime >= 600.

// ---------- Art palettes (cloak, cloakD, cloakL, trim, eye) ----------
const H2_ART = {
  duelist:   { cloak: P.steel,  cloakD: P.steelD,  cloakL: P.steelL,  trim: P.gold,    eye: P.redL  },
  warlock:   { cloak: P.poisonD,cloakD: P.shadow,  cloakL: P.poison,  trim: P.bronze,  eye: P.toxic },
  trapper:   { cloak: P.wood,   cloakD: P.woodD,   cloakL: P.woodL,   trim: P.iron,    eye: P.emberL},
  voidcaller:{ cloak: P.void,   cloakD: P.shadow,  cloakL: P.purpleL, trim: P.mana,    eye: P.manaL },
  warder:    { cloak: P.iceD,   cloakD: P.blueD,   cloakL: P.ice,     trim: P.shardL,  eye: P.shardL},
};

// ---------- Sprites (recoloured hunter, 16x18, feet anchored) ----------
defineAnim('char_h2_duelist',    16, 18, 4, (p, f) => { drawHeroBody(p, f, 'h2_duelist',    H2_ART.duelist);    p.outline(P.ink); }, { anchor: [8, 17], fps: 9 });
defineAnim('char_h2_warlock',    16, 18, 4, (p, f) => { drawHeroBody(p, f, 'h2_warlock',    H2_ART.warlock);    p.outline(P.ink); }, { anchor: [8, 17], fps: 9 });
defineAnim('char_h2_trapper',    16, 18, 4, (p, f) => { drawHeroBody(p, f, 'h2_trapper',    H2_ART.trapper);    p.outline(P.ink); }, { anchor: [8, 17], fps: 9 });
defineAnim('char_h2_voidcaller', 16, 18, 4, (p, f) => { drawHeroBody(p, f, 'h2_voidcaller', H2_ART.voidcaller); p.outline(P.ink); }, { anchor: [8, 17], fps: 9 });
defineAnim('char_h2_warder',     16, 18, 4, (p, f) => { drawHeroBody(p, f, 'h2_warder',     H2_ART.warder);     p.outline(P.ink); }, { anchor: [8, 17], fps: 9 });

// ---------- Characters ----------
const C = (o) => Characters.register(o);

// 1) Duelist — close-range fencer: faster attacks + a little crit, but frail.
//    Pairs with the soul-whip's directional sweeps.
C({
  id: 'h2_duelist', name: '魂刃決鬥者',
  desc: '射速 +12%、暴擊 +5%，但生命上限 -12。起始武器：魂鞭。',
  sprite: 'char_h2_duelist', startWeapon: 'w_whip',
  art: H2_ART.duelist,
  passive: (s) => {
    s.fireRateMult *= 1.12;
    s.critChance += 0.05;
    s.maxHp -= 12;
  },
  unlock: { type: 'gold', cost: 320 },
});

// 2) Warlock — attrition caster: wider, stronger domains, but slower on foot.
//    Pairs with the lingering venom fog (a domain weapon).
C({
  id: 'h2_warlock', name: '腐蝕巫師',
  desc: '範圍 +12%、傷害 +8%，但移速 -8%。起始武器：劇毒霧域。',
  sprite: 'char_h2_warlock', startWeapon: 'g_venomfog',
  art: H2_ART.warlock,
  passive: (s) => {
    s.area *= 1.12;
    s.damageMult *= 1.08;
    s.speed *= 0.92;
  },
  unlock: { type: 'gold', cost: 360 },
});

// 3) Trapper — zoner: extra pierce + stronger knockback to keep foes off you,
//    paid for with a slower fire rate. Pairs with proximity mines.
C({
  id: 'h2_trapper', name: '陷阱師',
  desc: '穿透 +1、擊退 +25%，但射速 -8%。起始武器：魂能地雷。',
  sprite: 'char_h2_trapper', startWeapon: 'g_mine',
  art: H2_ART.trapper,
  passive: (s) => {
    s.pierceAdd += 1;
    s.knockbackMult *= 1.25;
    s.fireRateMult *= 0.92;
  },
  unlock: { type: 'gold', cost: 340 },
});

// 4) Voidcaller — HIDDEN glass-cannon: heavy damage + area, very low health.
//    Pairs with the gravity-well weapon. Unlocked by lifetime kills.
//    NEW condition 'kills_5000' — see header note (cumulative META.stats.kills).
C({
  id: 'h2_voidcaller', name: '虛空喚者',
  desc: '傷害 +18%、範圍 +10%，但生命上限 -22。起始武器：奇異點。',
  sprite: 'char_h2_voidcaller', startWeapon: 'g_blackhole',
  art: H2_ART.voidcaller,
  passive: (s) => {
    s.damageMult *= 1.18;
    s.area *= 1.10;
    s.maxHp -= 22;
  },
  unlock: { type: 'achievement', condition: 'kills_5000', hint: '累計擊殺 5000 解鎖。' },
});

// 5) Warder — HIDDEN endurance survivor: light regen + lifesteal, traded for a
//    softer offense so survivability never stacks too high. Pairs with the
//    burning aura. Unlocked by surviving a single long run.
//    NEW condition 'survive_600' — see header note (single-run time >= 600s).
C({
  id: 'h2_warder', name: '恆冬守望者',
  desc: '生命回復 +1.2/秒、吸血 +4%，但傷害 -8%。起始武器：灼蝕光環。',
  sprite: 'char_h2_warder', startWeapon: 'w_aura',
  art: H2_ART.warder,
  passive: (s) => {
    s.hpRegen += 1.2;
    s.lifesteal += 0.04;
    s.damageMult *= 0.92;
  },
  unlock: { type: 'achievement', condition: 'survive_600', hint: '單局存活 600 秒解鎖。' },
});
